from collections import Counter
import math

def ngrams(tokens: list[str], n: int) -> Counter:
    return Counter(tuple(tokens[i:i+n]) for i in range(len(tokens) - n + 1))

def modified_precision(candidate: list[str], references: list[list[str]], n: int) -> tuple[int, int]:
    """Return (clipped_match_count, candidate_ngram_count) for order n."""
    cand_ngrams = ngrams(candidate, n)
    # Max count for each n-gram across all references
    max_ref_counts: Counter = Counter()
    for ref in references:
        ref_ngrams = ngrams(ref, n)
        for gram, cnt in ref_ngrams.items():
            max_ref_counts[gram] = max(max_ref_counts[gram], cnt)
    clipped = sum(min(cnt, max_ref_counts[gram]) for gram, cnt in cand_ngrams.items())
    return clipped, sum(cand_ngrams.values())

def brevity_penalty(candidate: list[str], references: list[list[str]]) -> float:
    c = len(candidate)
    r = min((abs(len(ref) - c), len(ref)) for ref in references)[1]
    return 1.0 if c > r else math.exp(1 - r / c)

def bleu(
    candidate: list[str],
    references: list[list[str]],
    max_n: int = 4,
    weights: list[float] | None = None,
    smoothing: float = 1e-10,
) -> float:
    """Corpus-level BLEU for a single candidate-reference pair."""
    if weights is None:
        weights = [1 / max_n] * max_n
    bp = brevity_penalty(candidate, references)
    log_avg = 0.0
    for n, w in enumerate(weights, 1):
        matched, total = modified_precision(candidate, references, n)
        pn = matched / max(total, 1)
        log_avg += w * math.log(max(pn, smoothing))
    return bp * math.exp(log_avg)

# Example
ref  = 'the cat sat on the mat'.split()
cand = 'the cat slept on the floor'.split()
score = bleu(cand, [ref])
print(f'BLEU-4: {score:.4f}')  # ~0.1897 (3/5 bigrams match, 2/4 trigrams miss)
